import cadquery as cq

# Central hub with cylindrical arms ending in hemispheres
# Six arms extending in +X, -X, +Y, -Y, +Z, -Z directions

r = 8       # radius of cylinders
L = 20      # length of each arm from center

# Central cube to act as hub
result = cq.Workplane("XY").box(2*r, 2*r, 2*r)

# Function to create an arm (cylinder + hemisphere) along a direction
def make_arm(direction):
    # Create cylinder along Z, then rotate
    arm = cq.Workplane("XY").cylinder(L, r, centered=(True, True, False))
    # Add hemisphere at top
    arm = arm.union(cq.Workplane("XY").sphere(r).translate((0, 0, L)))

    if direction == "+Z":
        return arm
    elif direction == "-Z":
        return arm.rotate((0,0,0), (1,0,0), 180)
    elif direction == "+X":
        return arm.rotate((0,0,0), (0,1,0), 90)
    elif direction == "-X":
        return arm.rotate((0,0,0), (0,1,0), -90)
    elif direction == "+Y":
        return arm.rotate((0,0,0), (1,0,0), -90)
    elif direction == "-Y":
        return arm.rotate((0,0,0), (1,0,0), 90)

for d in ["+X", "-X", "+Y", "-Y", "+Z", "-Z"]:
    result = result.union(make_arm(d))
